var users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  username: text("username").notNull().unique(),
  email: text("email"),
  password: text("password").notNull(),
  role: userRoleEnum("role").notNull().default("agent"),
  // Deprecated - use user_roles table instead
  firstName: text("first_name"),
  lastName: text("last_name"),
  // Agent telephony settings
  callbackPhone: text("callback_phone"),
  // Phone number to call agent for click-to-call
  sipExtension: text("sip_extension"),
  // Optional SIP extension for WebRTC
  // TOTP/Google Authenticator MFA fields
  mfaEnabled: boolean("mfa_enabled").notNull().default(false),
  totpSecret: text("totp_secret"),
  // Encrypted TOTP secret
  backupCodes: jsonb("backup_codes").$type(),
  // Array of backup codes
  usedBackupCodes: jsonb("used_backup_codes").$type().default([]),
  // Track used codes
  mfaEnrolledAt: timestamp("mfa_enrolled_at"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow()
}, (table) => ({
  emailIdx: index("users_email_idx").on(table.email),
  usernameIdx: index("users_username_idx").on(table.username)
}));
var passwordResetTokens = pgTable("password_reset_tokens", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  token: varchar("token", { length: 64 }).notNull().unique(),
  userId: varchar("user_id", { length: 36 }),
  clientUserId: varchar("client_user_id", { length: 36 }),
  email: text("email").notNull(),
  userType: text("user_type").notNull().default("internal"),
  expiresAt: timestamp("expires_at").notNull(),
  usedAt: timestamp("used_at"),
  createdAt: timestamp("created_at").notNull().defaultNow()
}, (table) => ({
  tokenIdx: index("password_reset_tokens_token_idx").on(table.token),
  emailIdx: index("password_reset_tokens_email_idx").on(table.email)
}));
