var leads = pgTable("leads", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  contactId: varchar("contact_id").references(() => contacts.id, { onDelete: "set null" }),
  contactName: text("contact_name"),
  contactEmail: text("contact_email"),
  campaignId: varchar("campaign_id").references(() => campaigns.id, { onDelete: "set null" }),
  // Link to call recording (if lead came from dialer campaign)
  // NOTE: References dialer_call_attempts (new dialer system), not call_attempts (legacy)
  callAttemptId: varchar("call_attempt_id").references(() => dialerCallAttempts.id, { onDelete: "set null" }),
  recordingUrl: text("recording_url"),
  // Original Telnyx URL (may expire after 10 min)
  recordingS3Key: text("recording_s3_key"),
  // Permanent S3 storage key for recordings
  telnyxRecordingId: text("telnyx_recording_id"),
  // Stable Telnyx recording ID for on-demand URL generation
  recordingProvider: text("recording_provider").default("telnyx"),
  // Provider: telnyx | elevenlabs
  callDuration: integer("call_duration"),
  // Duration in seconds
  dialedNumber: text("dialed_number"),
  // Phone number that was dialed
  telnyxCallId: text("telnyx_call_id"),
  // CRITICAL: Telnyx call control ID for finding recordings
  agentId: varchar("agent_id").references(() => users.id),
  // Agent who qualified the lead
  qaStatus: qaStatusEnum("qa_status").notNull().default("new"),
  // Account snapshot fields (for denormalized access)
  accountId: varchar("account_id").references(() => accounts.id, { onDelete: "set null" }),
  accountName: text("account_name"),
  accountIndustry: text("account_industry"),
  // Wrong Person Answered Tracking
  originalContactId: varchar("original_contact_id").references(() => contacts.id),
  // Contact that was originally dialed
  actualContactId: varchar("actual_contact_id").references(() => contacts.id),
  // Contact who actually answered (qualified person)
  wrongPersonAnswered: boolean("wrong_person_answered").default(false),
  // Flag if different person answered
  checklistJson: jsonb("checklist_json"),
  approvedAt: timestamp("approved_at"),
  approvedById: varchar("approved_by_id").references(() => users.id),
  rejectedReason: text("rejected_reason"),
  rejectedAt: timestamp("rejected_at"),
  rejectedById: varchar("rejected_by_id").references(() => users.id),
  notes: text("notes"),
  customFields: jsonb("custom_fields"),
  // AI-Powered QA Fields
  transcript: text("transcript"),
  // Call transcription from AssemblyAI
  transcriptionStatus: text("transcription_status"),
  // pending, processing, completed, failed
  structuredTranscript: jsonb("structured_transcript"),
  // Parsed conversation with speaker labels (Agent vs Prospect)
  recordingStatus: text("recording_status"),
  // pending, fetching, completed, failed
  aiScore: numeric("ai_score", { precision: 5, scale: 2 }),
  // AI qualification score (0-100)
  aiAnalysis: jsonb("ai_analysis"),
  // Detailed AI analysis results
  aiQualificationStatus: text("ai_qualification_status"),
  // qualified, not_qualified, needs_review
  qaData: jsonb("qa_data"),
  // Extracted custom QA field values {content_interest: "Yes", company_status: "Active", etc.}
  // Client Submission Tracking
  submittedToClient: boolean("submitted_to_client").default(false),
  submittedAt: timestamp("submitted_at"),
  submissionResponse: jsonb("submission_response"),
  // Client API/form response
  // Lead Delivery Tracking (Webhook/API)
  deliveredAt: timestamp("delivered_at"),
  // When lead was delivered via webhook/API
  deliveredById: varchar("delivered_by_id").references(() => users.id),
  // User who marked lead as delivered
  deliverySource: leadDeliverySourceEnum("delivery_source"),
  // auto_webhook or manual
  deliveryNotes: text("delivery_notes"),
  // Optional notes about delivery
  // Lead Verification (LinkedIn or On-Call)
  verificationStatus: leadVerificationStatusEnum("verification_status"),
  verificationId: varchar("verification_id"),
  // Reference to lead_verifications record
  qaDecision: text("qa_decision"),
  // Clear reason why lead needs review/was rejected
  // Publishing (QA approved → PM Review → Published for client portal)
  publishedAt: timestamp("published_at"),
  // When lead was published
  publishedBy: varchar("published_by").references(() => users.id),
  // User who published the lead
  // Project Management Review (PM approval required after QA approval)
  pmApprovedAt: timestamp("pm_approved_at"),
  // When PM approved the lead
  pmApprovedBy: varchar("pm_approved_by").references(() => users.id),
  // PM who approved
  pmRejectedAt: timestamp("pm_rejected_at"),
  // When PM rejected the lead
  pmRejectedBy: varchar("pm_rejected_by").references(() => users.id),
  // PM who rejected
  pmRejectionReason: text("pm_rejection_reason"),
  // Reason for PM rejection
  // LinkedIn Image Verification
  linkedinImageUrl: text("linkedin_image_url"),
  // S3 URL of LinkedIn screenshot
  linkedinVerificationData: jsonb("linkedin_verification_data"),
  // {extractedName, extractedPosition, extractedCompany, confidence, matchScore, verified}
  linkedinUrl: text("linkedin_url"),
  // LinkedIn profile URL (simpler verification method)
  verifiedAt: timestamp("verified_at"),
  // When lead was verified
  verifiedBy: varchar("verified_by").references(() => users.id),
  // Agent who verified the lead
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
  // Soft Delete
  deletedAt: timestamp("deleted_at"),
  // When lead was soft deleted
  deletedById: varchar("deleted_by_id").references(() => users.id)
  // User who deleted the lead
}, (table) => ({
  qaStatusIdx: index("leads_qa_status_idx").on(table.qaStatus),
  campaignIdx: index("leads_campaign_idx").on(table.campaignId),
  callAttemptIdx: index("leads_call_attempt_idx").on(table.callAttemptId),
  deletedAtIdx: index("leads_deleted_at_idx").on(table.deletedAt),
  contactIdx: index("leads_contact_idx").on(table.contactId),
  accountIdx: index("leads_account_idx").on(table.accountId),
  agentIdx: index("leads_agent_idx").on(table.agentId),
  createdIdx: index("leads_created_idx").on(table.createdAt)
}));
