var callSessions = pgTable("call_sessions", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  callJobId: varchar("call_job_id").references(() => callJobs.id, { onDelete: "cascade" }),
  telnyxCallId: text("telnyx_call_id"),
  telephonyProviderId: varchar("telephony_provider_id"),
  telephonyProviderType: varchar("telephony_provider_type", { length: 32 }),
  telephonyProviderName: text("telephony_provider_name"),
  providerCallId: text("provider_call_id"),
  telephonyRoutingMode: varchar("telephony_routing_mode", { length: 16 }),
  telephonySelectionReason: text("telephony_selection_reason"),
  telephonyCostPerMinute: real("telephony_cost_per_minute"),
  telephonyCostPerCall: real("telephony_cost_per_call"),
  telephonyCurrency: varchar("telephony_currency", { length: 3 }),
  telnyxRecordingId: text("telnyx_recording_id"),
  // Stable Telnyx recording ID for on-demand URL generation
  recordingProvider: text("recording_provider").default("telnyx"),
  // Provider: telnyx | elevenlabs
  fromNumber: text("from_number"),
  // Added to fix schema drift 
  callerNumberId: text("caller_number_id"),
  fromDid: text("from_did"),
  routingDecisionId: text("routing_decision_id"),
  toNumberE164: text("to_number_e164").notNull(),
  startedAt: timestamp("started_at").notNull().defaultNow(),
  endedAt: timestamp("ended_at"),
  durationSec: integer("duration_sec"),
  recordingUrl: text("recording_url"),
  status: callSessionStatusEnum("status").notNull().default("connecting"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  // Recording storage fields
  recordingS3Key: text("recording_s3_key"),
  // S3/GCS key for permanent storage
  recordingDurationSec: integer("recording_duration_sec"),
  // Duration of recording
  recordingStatus: recordingStatusEnum("recording_status").default("pending"),
  // Recording lifecycle
  recordingFormat: text("recording_format").default("mp3"),
  // Audio format (mp3/wav)
  recordingFileSizeBytes: integer("recording_file_size_bytes"),
  // File size in bytes
  // Post-call analysis lifecycle tracking
  analysisStatus: analysisStatusEnum("analysis_status").default("pending"),
  analysisFailedAt: timestamp("analysis_failed_at"),
  analysisRetryCount: integer("analysis_retry_count").default(0),
  // Unified agent type tracking (human or AI)
  agentType: agentTypeEnum("agent_type").notNull().default("human"),
  agentUserId: varchar("agent_user_id").references(() => users.id, { onDelete: "set null" }),
  // Human agent
  // AI agent metadata (populated when agentType = 'ai')
  aiAgentId: text("ai_agent_id"),
  // ElevenLabs agent ID
  aiConversationId: text("ai_conversation_id"),
  // ElevenLabs conversation ID
  aiTranscript: text("ai_transcript"),
  // Full conversation transcript
  aiAnalysis: jsonb("ai_analysis"),
  // AI-generated call analysis (outcome, summary, sentiment)
  aiDisposition: text("ai_disposition"),
  // AI-determined disposition label
  // Campaign context (for AI calls that may not have callJobId)
  campaignId: varchar("campaign_id").references(() => campaigns.id, { onDelete: "cascade" }),
  contactId: varchar("contact_id").references(() => contacts.id, { onDelete: "set null" }),
  queueItemId: varchar("queue_item_id")
  // Reference to campaign_queue item
}, (table) => ({
  callJobIdx: index("call_sessions_call_job_idx").on(table.callJobId),
  telnyxCallIdx: index("call_sessions_telnyx_call_idx").on(table.telnyxCallId),
  telephonyProviderIdx: index("call_sessions_telephony_provider_idx").on(table.telephonyProviderId),
  statusIdx: index("call_sessions_status_idx").on(table.status),
  agentTypeIdx: index("call_sessions_agent_type_idx").on(table.agentType),
  campaignIdx: index("call_sessions_campaign_idx").on(table.campaignId),
  contactIdx: index("call_sessions_contact_idx").on(table.contactId),
  aiConversationIdx: index("call_sessions_ai_conversation_idx").on(table.aiConversationId),
  recordingStatusIdx: index("call_sessions_recording_status_idx").on(table.recordingStatus),
  analysisStatusIdx: index("call_sessions_analysis_status_idx").on(table.analysisStatus)
}));
