  behavioralAssessment: jsonb("behavioral_assessment"),
  // {strengths[], weaknesses[], flags[]}
  issueFlags: jsonb("issue_flags"),
  // [{type, severity, description, evidence, transcriptMoment}]
  transcriptAnnotations: jsonb("transcript_annotations"),
  // [{turnIndex, annotation, category}]
  summary: text("summary"),
  // Metadata
  analysisModel: text("analysis_model"),
