  disposition: callDispositionEnum("disposition"),
  startedAt: timestamp("started_at"),
  endedAt: timestamp("ended_at"),
  duration: integer("duration"),
  notes: text("notes"),
  // Wrong Person Answered Tracking
  originalContactId: varchar("original_contact_id").references(() => contacts.id),
  // Contact that was dialed
  actualContactId: varchar("actual_contact_id").references(() => contacts.id),
  // Contact who actually answered
  wrongPersonAnswered: boolean("wrong_person_answered").default(false),
  // Flag if different person answered
  // AMD/Voicemail Tracking
  amdResult: amdResultEnum("amd_result"),
  // human | machine | unknown
  amdConfidence: numeric("amd_confidence", { precision: 3, scale: 2 }),
  // 0.00 - 1.00
  vmAssetId: varchar("vm_asset_id").references(() => voicemailAssets.id),
  // Voicemail asset used
  vmDelivered: boolean("vm_delivered").default(false),
  // Was VM successfully delivered
  vmDurationSec: integer("vm_duration_sec"),
