  wrapupSeconds: integer("wrapup_seconds"),
  // Time spent in wrap-up state
  scriptVersionId: varchar("script_version_id"),
  // FK to call_scripts (version tracking)
  qaLocked: boolean("qa_locked").default(false),
  // Prevents editing after QA review
  createdAt: timestamp("created_at").notNull().defaultNow()
