var selectionContexts = pgTable("selection_contexts", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").references(() => users.id, { onDelete: "cascade" }).notNull(),
  entityType: entityTypeEnum("entity_type").notNull(),
  selectionType: selectionTypeEnum("selection_type").notNull(),
  // 'explicit' or 'filtered'
  ids: text("ids").array(),
  // For explicit selections (≤10k records)
  filterGroup: jsonb("filter_group"),
  // For filtered selections (all matching)
  totalCount: integer("total_count").notNull(),
  // Total records in selection
  createdAt: timestamp("created_at").notNull().defaultNow(),
  expiresAt: timestamp("expires_at").notNull()
  // 15 min from creation
}, (table) => ({
  userIdx: index("selection_contexts_user_idx").on(table.userId),
  expiresIdx: index("selection_contexts_expires_idx").on(table.expiresAt)
}));
var filterFieldRegistry = pgTable("filter_field_registry", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  entity: text("entity").notNull(),
  // 'contact', 'account', 'campaign', etc.
  key: text("key").notNull(),
  // Field key in database (e.g., 'linkedin_url', 'job_title')
  label: text("label").notNull(),
  // Display name (e.g., 'LinkedIn Profile URL')
  type: text("type").notNull(),
  // 'string', 'number', 'boolean', 'array', 'date'
  operators: text("operators").array().notNull(),
  // Allowed operators for this field type
  category: filterFieldCategoryEnum("category").notNull(),
  // Categorization for UI grouping
  isCustom: boolean("is_custom").notNull().default(false),
  // Custom vs. system field
  visibleInFilters: boolean("visible_in_filters").notNull().default(true),
  // Show in filter UI
  description: text("description"),
  // Helper text for users
  sortOrder: integer("sort_order").default(0),
  // Display order within category
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow()
}, (table) => ({
  entityKeyIdx: index("filter_field_registry_entity_key_idx").on(table.entity, table.key),
  categoryIdx: index("filter_field_registry_category_idx").on(table.category),
  visibleIdx: index("filter_field_registry_visible_idx").on(table.visibleInFilters)
}));
