  // Batching Settings
  batchSize: integer("batch_size").default(5e3),
  batchGapMinutes: integer("batch_gap_minutes").default(15),
  seedTestBatch: boolean("seed_test_batch").default(false),
  // Throttling Settings
  globalTps: integer("global_tps").default(10),
  perDomainCaps: jsonb("per_domain_caps"),
  // { "gmail.com": 500, "outlook.com": 300 }
  frequencyCap: integer("frequency_cap"),
  // max emails per contact per week
  status: text("status").default("active").notNull(),
  // 'active' or 'suspended'
