var voicemailMachinePolicySchema = external_exports.object({
  action: external_exports.enum(["leave_voicemail", "schedule_callback", "drop_silent"]),
  message_type: external_exports.enum(["tts", "audio_file"]).optional(),
  tts_voice_id: external_exports.string().optional(),
  audio_asset_id: external_exports.string().optional(),
  template_id: external_exports.string().optional(),
  message_max_sec: external_exports.number().min(1).max(120).optional(),
  max_vm_per_contact: external_exports.number().min(1).max(10).optional(),
  vm_cooldown_hours: external_exports.number().min(1).max(720).optional(),
  campaign_daily_vm_cap: external_exports.number().min(1).optional(),
  vm_local_time_window: external_exports.object({
    start_hhmm: external_exports.string().regex(/^\d{2}:\d{2}$/),
    end_hhmm: external_exports.string().regex(/^\d{2}:\d{2}$/)
  }).optional(),
  restricted_region_block: external_exports.boolean().optional()
});
var amdConfigurationSchema = external_exports.object({
  enabled: external_exports.boolean(),
  confidence_threshold: external_exports.number().min(0).max(1),
  decision_timeout_ms: external_exports.number().min(1e3).max(5e3),
  uncertain_fallback: external_exports.enum(["route_as_human", "voicemail_policy"]),
  machine_policy: voicemailMachinePolicySchema.optional()
});
var powerDialSettingsSchema = external_exports.object({
  pacing_ratio: external_exports.number().min(1).max(3),
  max_concurrent_per_agent: external_exports.number().min(1).max(3),
  ring_timeout_sec: external_exports.number().min(10).max(120),
  abandon_rate_target_pct: external_exports.number().min(0).max(20),
  distribution_strategy: external_exports.enum(["round_robin", "least_recently_served", "skill_based"]),
  retry_rules: external_exports.any().optional(),
  quiet_hours: external_exports.any().optional(),
  max_daily_attempts_per_contact: external_exports.number().min(1).max(20).optional(),
  amd: amdConfigurationSchema.optional()
});
var verificationEligibilityStatusEnum = pgEnum("verification_eligibility_status", [
  "Eligible",
  "Out_of_Scope",
  "Ineligible_Cap_Reached",
  "Ineligible_Recently_Submitted",
  // Submitted in last 2 years - auto-excluded
  "Pending_Email_Validation",
  "Ineligible_Email_Invalid"
]);
