var verificationQaStatusEnum = pgEnum("verification_qa_status", ["Unreviewed", "Flagged", "Passed", "Rejected"]);
var verificationEmailStatusEnum = pgEnum("verification_email_status", [
  "valid",
  // SMTP confirmed deliverable OR DNS verified with high confidence
  "invalid",
  // Hard failures: syntax errors, no MX, mailbox disabled, disposable, spam trap
  "unknown",
  // Cannot reliably determine (SMTP blocked, timeout, greylisting, ambiguous response)
  "acceptable"
  // Catch-all/accept-all OR risk factors but likely deliverable
]);
var verificationSourceTypeEnum = pgEnum("verification_source_type", ["Client_Provided", "New_Sourced"]);
var addressEnrichmentStatusEnum = pgEnum("address_enrichment_status", ["not_needed", "pending", "in_progress", "completed", "failed"]);
var phoneEnrichmentStatusEnum = pgEnum("phone_enrichment_status", ["not_needed", "pending", "in_progress", "completed", "failed"]);
